type Tab = 'CHALLENGE' | 'QUESTS' | 'BIRDS' | 'STORE' | 'ROYALE_PASS' | 'LUCK_ROYALE' | 'SOCIAL' | 'LEADERBOARD' | 'ESPORTS' | 'PROFILE';

interface DashboardProps {
    playerData: Player;
    onStartMatchmaking: () => void;
    onMatchFound: (match: Match) => void;
    onCancelMatchmaking: () => void;
    isMatchmaking: boolean;
    onInviteFriend: (inviteeUid: string) => void;
    onStartSpectating: (matchId: string) => void;
    onStartMinigame: () => void;
    onEnterRoom: (room: CustomRoom) => void;
    inviteError?: string | null;
}

const AnimatedNumber: React.FC<{ value: number }> = ({ value }) => {
    const [currentValue, setCurrentValue] = useState(value);
    const prevValueRef = useRef(value);

    useEffect(() => {
        if (prevValueRef.current === value) return;
        const start = prevValueRef.current;
        const end = value;
        const duration = 500;
        let startTime: number | null = null;
        const animate = (timestamp: number) => {
            if (!startTime) startTime = timestamp;
            const progress = Math.min((timestamp - startTime) / duration, 1);
            setCurrentValue(Math.floor(start + (end - start) * progress));
            if (progress < 1) {
                requestAnimationFrame(animate);
            } else {
                prevValueRef.current = value;
            }
        };
        requestAnimationFrame(animate);
    }, [value]);
    return <span>{currentValue}</span>;
};

const SettingsIcon = () => <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756.2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>;
const MailIcon: React.FC<{ hasUnread: boolean }> = ({ hasUnread }) => <div className="relative"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" /></svg>{hasUnread && <div className="absolute top-0 right-0 w-2.5 h-2.5 bg-red-500 rounded-full border border-black animate-pulse"></div>}</div>;
const LogoutIcon = () => <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>;

// Side Icon Button
const SideIconButton: React.FC<{ icon: string, label: string, onClick: () => void, indicator?: boolean, color?: string }> = ({ icon, label, onClick, indicator, color = "bg-gray-800" }) => (
    <button onClick={onClick} className={`w-14 h-14 md:w-16 md:h-16 rounded-xl border-2 border-gray-600 ${color} flex flex-col items-center justify-center relative shadow-lg hover:scale-105 transition-transform active:scale-95`}>
        {indicator && <div className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border border-white animate-pulse z-10"></div>}
        <span className="text-2xl md:text-3xl drop-shadow-md">{icon}</span>
        <span className="text-[9px] md:text-[10px] font-bold uppercase mt-1 text-gray-200">{label}</span>
    </button>
);

const NavTabButton: React.FC<{ label: string, icon: string, onClick: () => void }> = ({ label, icon, onClick }) => (
    <button onClick={onClick} className="flex flex-col items-center justify-center px-4 py-1 text-gray-400 hover:text-white transition-colors">
        <span className="text-2xl mb-1 filter drop-shadow-sm">{icon}</span>
        <span className="text-[10px] font-bold uppercase tracking-wider">{label}</span>
    </button>
);

const getPrimeLevel = (totalGemsToppedUp: number = 0): number => {
    if (totalGemsToppedUp >= 20000) return 8;
    if (totalGemsToppedUp >= 15000) return 7;
    if (totalGemsToppedUp >= 10000) return 6;
    if (totalGemsToppedUp >= 5000) return 5;
    if (totalGemsToppedUp >= 4000) return 4;
    if (totalGemsToppedUp >= 3000) return 3;
    if (totalGemsToppedUp >= 2000) return 2;
    if (totalGemsToppedUp >= 1000) return 1;
    return 0;
};

const PrimeLevelDisplay: React.FC<{ level: number }> = ({ level }) => {
    if (level === 0) return null;
    return (
        <div className="ff-prime-level ml-2" title={`Prime Level ${level}`}>
            <span className="ff-prime-level-icon">⭐</span>
            <span className="ff-prime-level-text">{level}</span>
        </div>
    );
};

const Dashboard: React.FC<DashboardProps> = (props) => {
    const { playerData, onStartMatchmaking, onCancelMatchmaking, isMatchmaking, onEnterRoom } = props;
    const config = useGameConfig();
    const { lobbyBackground } = useContentConfig();
    const { musicVolume } = useSettings();
    const [activeTab, setActiveTab] = useState<Tab>('CHALLENGE');
    const [selectedMode, setSelectedMode] = useState<'rank' | 'minigame'>('rank');
    const [isSettingsOpen, setIsSettingsOpen] = useState(false);
    const [isTopUpModalOpen, setIsTopUpModalOpen] = useState(false);
    const [isMailboxOpen, setIsMailboxOpen] = useState(false);
    const [mailItems, setMailItems] = useState<MailItem[]>([]);
    const [matchmakingTime, setMatchmakingTime] = useState(0);
    const matchmakingIntervalRef = useRef<number | null>(null);
    const winterThemeActive = isWinterThemeActive();
    const [isCustomRoomModalOpen, setIsCustomRoomModalOpen] = useState(false);

    const { notifications } = useRealtime();
    const [viewingProfileUid, setViewingProfileUid] = useState<string | null>(null);
    const [matchmakingError, setMatchmakingError] = useState<string | null>(null);
    const [isClaiming, setIsClaiming] = useState(false);
    const [membershipModalInfo, setMembershipModalInfo] = useState<{type: 'weekly' | 'monthly'} | null>(null);
    const [isWinterverseModalOpen, setIsWinterverseModalOpen] = useState(false);
    const [isEventsModalOpen, setIsEventsModalOpen] = useState(false);
    const musicStarted = useRef(false);

    useEffect(() => {
        if (isMatchmaking) {
            setMatchmakingTime(0);
            matchmakingIntervalRef.current = window.setInterval(() => {
                setMatchmakingTime(prev => prev + 1);
            }, 1000);
        } else {
            if (matchmakingIntervalRef.current) {
                clearInterval(matchmakingIntervalRef.current);
                matchmakingIntervalRef.current = null;
            }
        }
        return () => {
            if (matchmakingIntervalRef.current) {
                clearInterval(matchmakingIntervalRef.current);
            }
        };
    }, [isMatchmaking]);

    useEffect(() => {
        const hideModal = sessionStorage.getItem('hideWinterverseModal') === 'true';
        if (!hideModal) {
            setTimeout(() => setIsWinterverseModalOpen(true), 1000);
        }
    }, []);

    const formatTime = (seconds: number) => {
        const minutes = Math.floor(seconds / 60);
        const remainingSeconds = seconds % 60;
        return `${String(minutes).padStart(2, '0')}:${String(remainingSeconds).padStart(2, '0')}`;
    };

    const NOTIF_STORAGE_KEY = `birdclash-lastReadNotifTimestamp-${playerData.uid}`;
    const hasUnreadGlobalNotifs = useMemo(() => {
        if (notifications.length > 0) {
            const lastReadTimestamp = parseInt(localStorage.getItem(NOTIF_STORAGE_KEY) || '0', 10);
            return notifications[0].timestamp > lastReadTimestamp;
        }
        return false;
    }, [notifications, NOTIF_STORAGE_KEY]);

    useEffect(() => {
        const unsub = playerService.listenToMail(playerData.uid, setMailItems);
        return () => unsub();
    }, [playerData.uid]);

    const hasUnreadMail = useMemo(() => mailItems.some(item => item.status === 'unread'), [mailItems]);

    const isWeeklyActive = playerData.weeklyMembershipExpires && playerData.weeklyMembershipExpires > Date.now();
    const isMonthlyActive = playerData.monthlyMembershipExpires && playerData.monthlyMembershipExpires > Date.now();

    useEffect(() => {
        const audioEl = document.getElementById('lobby-music') as HTMLAudioElement;
        if (!audioEl) return;

        const targetUrl = config.lobbyMusicUrl || 'https://cdn.pixabay.com/download/audio/2022/08/04/audio_2d81b016b8.mp3';
        if (audioEl.src !== targetUrl) {
            audioEl.src = targetUrl;
            audioEl.load();
        }

        audioEl.volume = musicVolume;

        const playMusic = () => {
            if (musicStarted.current || !audioEl.paused) {
                document.removeEventListener('click', playMusic);
                document.removeEventListener('touchstart', playMusic);
                return;
            }
            const playPromise = audioEl.play();
            if (playPromise !== undefined) {
                playPromise.then(() => {
                    musicStarted.current = true;
                    document.removeEventListener('click', playMusic);
                    document.removeEventListener('touchstart', playMusic);
                }).catch(() => {});
            }
        };
        document.addEventListener('click', playMusic, { once: true });
        document.addEventListener('touchstart', playMusic, { once: true });
        playMusic();
        return () => {
            if (audioEl) audioEl.pause();
            musicStarted.current = false;
            document.removeEventListener('click', playMusic);
            document.removeEventListener('touchstart', playMusic);
        };
    }, [musicVolume, config.lobbyMusicUrl]);

    const hasClaimableQuests = useMemo(() => {
        if (!playerData.quests) return false;
        return DAILY_QUESTS.some(quest => {
            const progress = playerData.quests?.progress[quest.id];
            return progress && progress.progress >= quest.target && !progress.claimed;
        });
    }, [playerData.quests]);

    const isDailyClaimAvailable = useMemo(() => {
        const now = Date.now();
        const todayStr = new Date(now).toISOString().split('T')[0];
        const weeklyActive = playerData.weeklyMembershipExpires && playerData.weeklyMembershipExpires > now;
        const weeklyClaimed = playerData.weeklyClaims?.includes(todayStr);
        const monthlyActive = playerData.monthlyMembershipExpires && playerData.monthlyMembershipExpires > now;
        const monthlyClaimed = playerData.monthlyClaims?.includes(todayStr);
        return (weeklyActive && !weeklyClaimed) || (monthlyActive && !monthlyClaimed);
    }, [playerData]);

    const equippedBird = useMemo(() => {
        if (!playerData.ownedBirds) return null;
        const birdId = playerData.equippedBirdId;
        if (birdId && playerData.ownedBirds[birdId]) return playerData.ownedBirds[birdId];
        const allBirds = Object.values(playerData.ownedBirds);
        return allBirds.length > 0 ? allBirds[0] : null;
    }, [playerData.ownedBirds, playerData.equippedBirdId]);

    const handleToggleMailbox = () => {
        setIsMailboxOpen(prev => !prev);
        if (!isMailboxOpen && notifications.length > 0) {
            localStorage.setItem(NOTIF_STORAGE_KEY, notifications[0].timestamp.toString());
        }
    };

    const handleClaim = async () => {
        if (!playerData.uid) return;
        setIsClaiming(true);
        try { const message = await claimDailyMembershipRewards(playerData.uid); toast.success(message); } 
        catch (e: any) { toast.error(e.message); } 
        finally { setIsClaiming(false); }
    };

    const handleStartSoloMatchmaking = () => {
        if (playerData.isBlacklisted) {
            toast.warn("⚠️ This ID is under suspicious activity. You can’t play ranked matches at the moment.");
            return;
        }
        if (!equippedBird) { toast.error("Please equip a bird from your Collection first!"); return; }
        setMatchmakingError(null);
        const fee = config.RANK_ENTRY_FEE_COINS;
        if (playerData.coins < fee) {
            const errorMsg = `Not enough coins! You need ${fee} to play.`;
            setMatchmakingError(errorMsg);
            toast.error(errorMsg);
            return;
        }
        onStartMatchmaking();
    };

    const hasBirds = playerData.ownedBirds && Object.keys(playerData.ownedBirds).length > 0;
    const primeLevel = getPrimeLevel(playerData.totalGemsToppedUp);

    const renderPanelContent = () => {
        const panelProps = { player: playerData };
        switch(activeTab) {
            case 'STORE': return <StoreScreen {...panelProps} />;
            case 'BIRDS': return <BirdsScreen {...panelProps} />;
            case 'SOCIAL': return <SocialScreen player={playerData} onInviteFriend={props.onInviteFriend} onStartSpectating={props.onStartSpectating} onViewProfile={setViewingProfileUid} />;
            case 'PROFILE': return <ProfileScreen {...panelProps} />;
            case 'ROYALE_PASS': return <RoyalePassScreen {...panelProps} />;
            case 'ESPORTS': return <EsportsScreen {...panelProps} />;
            case 'LEADERBOARD': return <Leaderboard onViewProfile={setViewingProfileUid} />;
            case 'LUCK_ROYALE': return <LuckRoyaleScreen {...panelProps} />;
            case 'QUESTS': return <QuestsScreen {...panelProps} />;
            default: return null;
        }
    };

    const showContentPanel = activeTab !== 'CHALLENGE';

    return (
        <div className="w-full h-full flex flex-col relative overflow-hidden" style={{ 
            backgroundImage: winterThemeActive 
                ? 'radial-gradient(ellipse at bottom, #1b2735 0%, #090a0f 100%)' 
                : `url('${lobbyBackground}')`,
            backgroundSize: 'cover',
            backgroundPosition: 'center',
            backgroundRepeat: 'no-repeat'
        }}>
            {winterThemeActive && <Snowfall />}

            {/* --- Top Bar --- */}
            <header className="absolute top-0 left-0 right-0 h-16 flex items-center justify-between px-4 z-20 bg-gradient-to-b from-black/80 to-transparent pointer-events-none">
                {/* Top Left: Player Profile */}
                <div className="flex items-center gap-3 pointer-events-auto cursor-pointer transition-transform hover:scale-105" onClick={() => setActiveTab('PROFILE')}>
                    <div className="relative">
                        <PlayerAvatar photoURL={playerData.photoURL} uid={playerData.uid} activeBadge={playerData.activeBadge} sizeClassName="w-12 h-12 rounded-lg border-2 border-gray-400 bg-gray-800" imgClassName="rounded-lg"/>
                        <div className="absolute -bottom-1 -right-1 bg-blue-600 text-white text-[10px] font-bold px-1.5 rounded-full border border-black shadow-sm">
                            {playerData.level}
                        </div>
                    </div>
                    <div className="flex flex-col">
                        <div className="flex items-center gap-2">
                            <span className="text-white font-bold text-shadow-sm font-pixel text-sm">{playerData.displayName || 'Player'}</span>
                            {primeLevel > 0 && <PrimeLevelDisplay level={primeLevel} />}
                        </div>
                        <PlayerRankDisplay player={playerData} className="text-xs text-gray-300" />
                    </div>
                </div>

                {/* Top Right: Currency & Settings */}
                <div className="flex items-center gap-3 pointer-events-auto">
                    {/* Currency Group */}
                    <div className="flex items-center gap-2 bg-black/40 backdrop-blur-md rounded-full p-1 pr-4 border border-gray-600 shadow-lg">
                        <div className="flex items-center gap-1">
                            <span className="text-xl">💰</span>
                            <span className="font-bold text-yellow-400 text-sm"><AnimatedNumber value={playerData.coins} /></span>
                        </div>
                        <div className="w-px h-4 bg-gray-500 mx-1"></div>
                        <div className="flex items-center gap-1 relative">
                            <span className="text-xl">💎</span>
                            <span className="font-bold text-purple-400 text-sm"><AnimatedNumber value={playerData.gems} /></span>
                            <button onClick={() => setIsTopUpModalOpen(true)} className="ml-2 w-5 h-5 bg-green-500 rounded-full text-black font-bold text-xs flex items-center justify-center hover:bg-green-400 shadow-sm">+</button>
                        </div>
                    </div>

                    {/* Quick Action Icons */}
                    <div className="flex gap-2">
                        {isDailyClaimAvailable && (
                            <button onClick={handleClaim} disabled={isClaiming} className="w-10 h-10 bg-gradient-to-br from-green-500 to-green-700 rounded-full flex items-center justify-center border-2 border-green-300 shadow-lg animate-pulse hover:scale-110 transition-transform">
                                {isClaiming ? <Spinner /> : <span className="text-xl">🎁</span>}
                            </button>
                        )}
                        <button onClick={handleToggleMailbox} className="w-10 h-10 bg-gray-800/80 rounded-full flex items-center justify-center border border-gray-600 hover:bg-gray-700 transition-colors relative">
                            <MailIcon hasUnread={hasUnreadMail || hasUnreadGlobalNotifs} />
                        </button>
                        <button onClick={() => setIsSettingsOpen(true)} className="w-10 h-10 bg-gray-800/80 rounded-full flex items-center justify-center border border-gray-600 hover:bg-gray-700 transition-colors">
                            <SettingsIcon />
                        </button>
                    </div>
                </div>
            </header>

            {/* --- Main Content Area --- */}
            <div className="flex-grow relative z-10 flex pt-16 pb-20 px-4">

                {/* Left Sidebar Actions */}
                <div className="flex flex-col gap-3 justify-center">
                    <SideIconButton icon="📜" label="Quests" onClick={() => setActiveTab('QUESTS')} indicator={hasClaimableQuests} />
                    <SideIconButton icon="🎟️" label="Pass" onClick={() => setActiveTab('ROYALE_PASS')} color="bg-gradient-to-br from-yellow-600 to-yellow-800 border-yellow-500" />
                    <SideIconButton icon="🎰" label="Royale" onClick={() => setActiveTab('LUCK_ROYALE')} color="bg-gradient-to-br from-purple-600 to-purple-800 border-purple-500" />
                    <SideIconButton icon="🎉" label="Events" onClick={() => setIsEventsModalOpen(true)} indicator={true} color="bg-blue-800 border-blue-500"/>
                </div>

                {/* Center Character Display */}
                <div className="flex-grow flex flex-col items-center justify-center relative">
                    {/* Character Model */}
                    <div className="relative transform transition-transform hover:scale-105 duration-300 cursor-pointer" onClick={() => setActiveTab('BIRDS')}>
                        {equippedBird ? (
                            <>
                                <div className="drop-shadow-[0_10px_20px_rgba(0,0,0,0.8)] filter">
                                    <BirdIcon 
                                        bird={equippedBird} 
                                        className="text-[12rem] md:text-[16rem] leading-none"
                                        imgClassName="w-48 h-48 md:w-64 md:h-64 object-contain"
                                    />
                                </div>
                                <div className="absolute -bottom-8 left-1/2 -translate-x-1/2 bg-black/60 backdrop-blur-sm px-4 py-1 rounded-full border border-gray-500 text-center whitespace-nowrap">
                                    <p className="text-yellow-400 font-bold text-sm tracking-wider uppercase font-pixel">{equippedBird.name}</p>
                                    <p className="text-gray-300 text-[10px]">Lvl {equippedBird.level} • Power {equippedBird.skillPower}</p>
                                </div>
                            </>
                        ) : (
                            <div className="text-center bg-black/40 p-4 rounded-xl border border-gray-600 backdrop-blur-sm">
                                <p className="text-gray-300 mb-2">No Bird Equipped</p>
                                <Button onClick={() => setActiveTab('BIRDS')} className="text-sm px-3 py-1">Select Bird</Button>
                            </div>
                        )}
                    </div>
                </div>

                {/* Right Sidebar Actions (Play) */}
                <div className="flex flex-col gap-3 justify-center items-end min-w-[180px]">

                    {/* Game Mode Selector */}
                    <div className="bg-black/60 backdrop-blur-md p-1 rounded-lg border border-gray-600 flex gap-1 mb-2">
                        <button 
                            onClick={() => setSelectedMode('rank')}
                            className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all ${selectedMode === 'rank' ? 'bg-yellow-500 text-black shadow-md' : 'text-gray-400 hover:text-white'}`}
                        >
                            RANKED
                        </button>
                        <button 
                            onClick={() => setSelectedMode('minigame')}
                            className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all ${selectedMode === 'minigame' ? 'bg-yellow-500 text-black shadow-md' : 'text-gray-400 hover:text-white'}`}
                        >
                            MINI-GAME
                        </button>
                    </div>

                    {isMatchmaking ? (
                        <div className="w-48 bg-black/80 backdrop-blur-md border-2 border-yellow-500 rounded-xl p-4 flex flex-col items-center shadow-[0_0_15px_rgba(234,179,8,0.3)]">
                            <p className="text-yellow-400 font-bold text-sm mb-1 animate-pulse">SEARCHING...</p>
                            <p className="text-white font-mono text-lg mb-3">{formatTime(matchmakingTime)}</p>
                            <Button onClick={onCancelMatchmaking} variant="danger" className="w-full !py-2 !text-xs">CANCEL</Button>
                        </div>
                    ) : (
                        <div className="flex flex-col gap-2 w-full items-end">
                             <Button
                                onClick={() => setIsCustomRoomModalOpen(true)}
                                variant="secondary"
                                className="w-full !py-2 !text-sm border-gray-500 hover:border-white"
                            >
                                CUSTOM ROOM
                            </Button>
                            <button
                                onClick={() => {
                                    if (selectedMode === 'rank') handleStartSoloMatchmaking();
                                    else props.onStartMinigame();
                                }}
                                disabled={!hasBirds && selectedMode === 'rank'}
                                className="w-full bg-gradient-to-b from-yellow-400 to-orange-600 border-b-4 border-orange-800 rounded-xl py-3 px-6 shadow-xl active:translate-y-1 active:border-b-0 transition-all hover:brightness-110 flex items-center justify-center gap-2 group"
                            >
                                <span className="font-pixel text-xl text-black drop-shadow-sm group-hover:scale-105 transition-transform">BATTLE</span>
                                <span className="text-2xl group-hover:rotate-12 transition-transform">⚔️</span>
                            </button>
                        </div>
                    )}
                    {matchmakingError && <p className="text-red-400 text-[10px] font-bold bg-black/50 px-2 py-1 rounded">{matchmakingError}</p>}
                </div>
            </div>

            {/* --- Bottom Navigation Dock --- */}
            <div className="absolute bottom-0 left-0 right-0 h-16 bg-gradient-to-t from-black to-transparent z-20 flex justify-center items-end pb-2">
                <div className="bg-black/60 backdrop-blur-lg border border-gray-600 rounded-full px-6 py-2 flex gap-4 shadow-2xl">
                    <NavTabButton label="Shop" icon="🛒" onClick={() => setActiveTab('STORE')} />
                    <NavTabButton label="Birds" icon="🐦" onClick={() => setActiveTab('BIRDS')} />
                    <NavTabButton label="Social" icon="👥" onClick={() => setActiveTab('SOCIAL')} />
