                        <div className="p-4 bg-gray-900/90 border-b border-gray-700 flex justify-between items-center">
                            <h2 className="font-pixel text-2xl text-yellow-400 tracking-wider flex items-center gap-3">
                                {activeTab === 'STORE' && '🛒 STORE'}
                                {activeTab === 'BIRDS' && '🐦 COLLECTION'}
                                {activeTab === 'SOCIAL' && '👥 SOCIAL'}
                                {activeTab === 'LEADERBOARD' && '🏆 LEADERBOARD'}
                                {activeTab === 'ESPORTS' && '🏅 ESPORTS'}
