  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const config = useGameConfig();

  const handleGoogleSignIn = async () => {
    setLoading(true);
    setError(null);
    // Fix: Use Firebase v8 namespaced provider.
    const provider = new firebase.auth.GoogleAuthProvider();
    try {
      // Fix: Use Firebase v8 namespaced signInWithPopup method.
      const result = await auth.signInWithPopup(provider);
      if (result.user) {
        await createPlayerProfile(result.user, config.DAILY_LOGIN_BONUS_COINS);
      }
    } catch (error: any) {
      setError(getFirebaseErrorMessage(error));
    } finally {
      setLoading(false);
    }
  };

  const handleEmailAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    try {
      if (isLogin) {
        // Fix: Use Firebase v8 namespaced signInWithEmailAndPassword method.
        const result = await auth.signInWithEmailAndPassword(email, password);
        if (result.user) {
          await createPlayerProfile(result.user, config.DAILY_LOGIN_BONUS_COINS);
        }
      } else {
        if (!displayName.trim()) {
          setError("Please enter a username.");
          setLoading(false);
          return;
        }
        // Fix: Use Firebase v8 namespaced createUserWithEmailAndPassword method.
        const result = await auth.createUserWithEmailAndPassword(email, password);
        if (result.user) {
          await result.user.updateProfile({ displayName });
          await createPlayerProfile(result.user, config.DAILY_LOGIN_BONUS_COINS);
        }
      }
    } catch (error: any) {
      setError(getFirebaseErrorMessage(error));
    } finally {
      setLoading(false);
    }
