                    </div>
                </div>
                {/* Reduced text size: text-4xl -> text-2xl */}
                <h1 className="text-2xl sm:text-3xl font-bold text-white mb-1 font-pixel" style={{ textShadow: '0 0 15px rgba(255,255,255,0.4), 3px 3px 0px #2c3e50' }}>
