                                            handleStartSoloMatchmaking();
                                        } else if (selectedMode === 'minigame') {
                                            props.onStartMinigame();
                                        }
                                    }}
                                    disabled={!hasBirds && selectedMode === 'rank'}
                                    className="w-full !py-2 !text-sm"
                                >
                                    START
                                </Button>
                            </div>

                            {matchmakingError && <p className="text-red-400 text-[10px] text-center">{matchmakingError}</p>}
                        </div>
                    </div>
                </div>
            </main>

            {/* Bottom Nav - Hidden on larger screens */}
            <div className="sm:hidden">
              <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} hasUnreadGlobalMessages={hasUnreadGlobalMessages} />
            </div>

             {/* Modal-like Panel for other tabs */}
             {showContentPanel && (
                <div className="absolute inset-0 bg-black/70 backdrop-blur-sm z-20 flex items-center justify-center" onClick={() => setActiveTab('CHALLENGE')}>
                    <div className="w-full h-full max-w-5xl max-h-[95vh] bg-[var(--ff-bg)] border-2 border-[var(--ff-border)] shadow-2xl flex flex-col m-2 sm:m-4" onClick={e => e.stopPropagation()}>
                        <div className="p-2 flex-shrink-0 border-b border-[var(--ff-border)] flex justify-between items-center bg-gray-900/90">
                            <h2 className="font-pixel text-lg sm:text-xl text-yellow-400">{activeTab.replace('_', ' ')}</h2>
                            <button onClick={() => setActiveTab('CHALLENGE')} className="text-2xl hover:text-yellow-400">&times;</button>
                        </div>
                        <div className="flex-grow overflow-hidden flex flex-col p-2">
