import React, { useState } from 'react';
import type { Player } from '../../types';
import Button from './common/Button';
import { useAuth } from '../hooks/useAuth';
import { spinGoldRoyale, spinDiamondRoyale } from '../services/playerService';
import { Spinner } from './common/Spinner';

interface LuckRoyaleScreenProps {
  player: Player;
}

const LuckRoyaleScreen: React.FC<LuckRoyaleScreenProps> = ({ player }) => {
  const { user } = useAuth();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [result, setResult] = useState('');
  const [isSpinning, setIsSpinning] = useState(false);
  const [rotation, setRotation] = useState(0);
  const [activeTab, setActiveTab] = useState<'gold' | 'diamond'>('gold');

  const handleSpin = async () => {
    if (!user || isSpinning) return;

    const spinFunction = activeTab === 'gold' ? spinGoldRoyale : spinDiamondRoyale;
    const cost = activeTab === 'gold' ? 100 : 9 * Math.pow(2, player.diamondSpins || 0);
    const currency = activeTab === 'gold' ? 'coins' : 'gems';

    if (player[currency] < cost) {
        setError(`Not enough ${currency}! You need ${cost}.`);
        return;
    }

    setIsSpinning(true);
    setLoading(true);
    setError('');
    setResult('');

    const fullSpins = Math.floor(Math.random() * 3) + 5;
    const newRotation = rotation + (fullSpins * 360);
    setRotation(newRotation);

    setTimeout(async () => {
        try {
            const spinResult = await spinFunction(user.uid);
            setResult(spinResult.message);
        } catch (e: any) {
            setError(e.message);
        } finally {
            setLoading(false);
            setIsSpinning(false);
        }
    }, 4000);
  };

  const goldSpins = player.goldSpins || 0;
  const diamondSpins = player.diamondSpins || 0;

  const currentCost = activeTab === 'gold' ? 100 : 9 * Math.pow(2, diamondSpins);
  const progress = activeTab === 'gold' ? (goldSpins % 1000) / 10 : (diamondSpins % 25) * 4;
  const maxProgress = activeTab === 'gold' ? 1000 : 25;
  const currentProgressCount = activeTab === 'gold' ? goldSpins % 1000 : diamondSpins % 25;

  return (
    <div className="w-full h-full flex flex-col space-y-2">
      <style>{`
        @keyframes flash-in {
            0% { opacity: 0; transform: scale(0.8); filter: brightness(3); }
            50% { opacity: 1; transform: scale(1.1); filter: brightness(1.5); }
            100% { opacity: 1; transform: scale(1); filter: brightness(1); }
        }
        .animate-flash-in { animation: flash-in 0.6s ease-out; }
      `}</style>

      {/* Tabs */}
      <div className="flex border-b-2 border-black flex-shrink-0">
        <button 
          onClick={() => setActiveTab('gold')}
          className={`flex-1 py-2 font-bold text-sm transition-colors ${activeTab === 'gold' ? 'bg-yellow-400 text-black' : 'bg-[#1a1a2e] text-white hover:bg-gray-800'}`}
        >
            Gold Royale
        </button>
        <button 
          onClick={() => setActiveTab('diamond')}
          className={`flex-1 py-2 font-bold text-sm transition-colors ${activeTab === 'diamond' ? 'bg-purple-400 text-black' : 'bg-[#1a1a2e] text-white hover:bg-gray-800'}`}
        >
            Diamond Royale
        </button>
      </div>

      <div className="flex-grow flex flex-col sm:flex-row gap-4 p-2 bg-gradient-to-br from-[#16213e] to-[#2c2c54] border-2 border-black shadow-[6px_6px_0px_#000000] relative overflow-hidden">
        <div className="absolute inset-0 bg-black/20 opacity-50 pointer-events-none"></div>
        <div className={`absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-72 h-72 rounded-full blur-3xl opacity-30 pointer-events-none ${activeTab === 'gold' ? 'bg-yellow-500' : 'bg-purple-500'}`}></div>

        {/* Left Side: Wheel */}
        <div className="flex-1 flex items-center justify-center relative z-10 min-h-[200px]">
             <div 
              className={`relative w-48 h-48 sm:w-64 sm:h-64 rounded-full border-4 shadow-lg flex items-center justify-center transition-transform duration-[4000ms] ease-out ${activeTab === 'gold' ? 'border-yellow-400 bg-yellow-900/50' : 'border-purple-400 bg-purple-900/50'}`}
              style={{ transform: `rotate(${rotation}deg)` }}
            >
                <div className={`absolute w-full h-full rounded-full bg-gradient-conic animate-spin ${activeTab === 'gold' ? 'from-yellow-500 via-orange-500 to-yellow-600' : 'from-purple-500 via-pink-500 to-blue-500'}`} style={{ animationDuration: activeTab === 'gold' ? '5s' : '3s' }}></div>
                <span className="text-6xl z-10 drop-shadow-lg">{activeTab === 'gold' ? '💰' : '💎'}</span>
            </div>
        </div>

        {/* Right Side: Info & Controls */}
        <div className="flex-1 flex flex-col justify-center space-y-4 relative z-10">
            <div className="text-center sm:text-left">
                <h3 className={`text-xl font-bold ${activeTab === 'gold' ? 'text-yellow-400' : 'text-purple-400'}`}>
                    {activeTab === 'gold' ? 'Gold Royale' : 'Diamond Royale'}
                </h3>
                <p className="text-xs text-gray-300 mt-1">
                    {activeTab === 'gold' 
                        ? 'Spin for coins! Guaranteed Epic Bird every 1000 spins.' 
                        : 'Spin for exclusive prizes! Champion NFT Card every 25 spins.'}
                </p>
            </div>

            {/* Progress */}
            <div className="w-full">
                <div className="flex justify-between text-xs mb-1">
                    <span>Milestone Progress</span>
                    <span>{currentProgressCount} / {maxProgress}</span>
                </div>
                <div className="w-full bg-black h-4 border-2 border-black p-0.5">
                    <div className={`h-full ${activeTab === 'gold' ? 'bg-yellow-400' : 'bg-purple-400'}`} style={{width: `${progress}%`}}></div>
                </div>
            </div>

            {/* Action */}
            <div className="space-y-2">
                <Button onClick={handleSpin} disabled={isSpinning} className="w-full !py-3 !text-lg">
                    {isSpinning ? <Spinner/> : `Spin for ${activeTab === 'gold' ? '💰' : '💎'} ${currentCost}`}
                </Button>

                <div className="h-8 flex items-center justify-center">
                    {error && <p className="text-red-400 text-xs font-bold">{error}</p>}
                    {result && !loading && <p className="text-green-300 text-sm font-semibold animate-flash-in">{result}</p>}
                    {loading && isSpinning && <p className="text-gray-400 text-xs">Spinning...</p>}
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

export default LuckRoyaleScreen;

import React, { useState, useMemo } from 'react';
import type { Player, RoyalePassTier } from '../types';
import { useAuth } from '../hooks/useAuth';
import { useContentConfig } from '../hooks/useContentConfig';
import { activateRoyalePass, claimRoyalePassReward } from '../services/playerService';
import Button from './common/Button';
import { Spinner } from './common/Spinner';
import { toast } from 'react-toastify';

interface RoyalePassScreenProps {
    player: Player;
}

const RoyalePassScreen: React.FC<RoyalePassScreenProps> = ({ player }) => {
    const { user } = useAuth();
    const { royalePassTiers, loading: contentLoading } = useContentConfig();
    const [loadingAction, setLoadingAction] = useState(false);
    const [claimingId, setClaimingId] = useState<string | null>(null);

    const playerPass = player.royalePass;

    const handleActivatePass = async () => {
        if (!user) return;
        if (!window.confirm("Activate the premium Royale Pass for 500 gems?")) return;
        setLoadingAction(true);
        try {
            await activateRoyalePass(user.uid);
            toast.success("Royale Pass Activated!");
        } catch (e: any) {
            toast.error(e.message);
        } finally {
            setLoadingAction(false);
        }
    };

    const handleClaim = async (tier: RoyalePassTier, rewardType: 'free' | 'premium') => {
        if (!user) return;
        const reward = rewardType === 'free' ? tier.freeReward : tier.premiumReward;
        if (!reward) return;

        setClaimingId(`${tier.id}-${rewardType}`);
        try {
            await claimRoyalePassReward(user.uid, tier.level, reward, rewardType);
            toast.success(`Claimed ${reward.name || 'reward'}!`);
        } catch (e: any) {
            toast.error(e.message);
        } finally {
            setClaimingId(null);
        }
    };

    const { currentLevel, totalXpForNextLevel, xpInCurrentLevel, xpForNextLevel } = useMemo(() => {
        if (!playerPass || royalePassTiers.length === 0) {
            return { currentLevel: 1, xpForNextLevel: 100, xpInCurrentLevel: 0, totalXpForNextLevel: 100 };
        }

        let level = 1;
        let totalXpForLevel = 0;
        for (const tier of royalePassTiers) {
            if (playerPass.xp >= tier.xp) {
                level = tier.level;
                totalXpForLevel = tier.xp;
            } else {
                break;
            }
        }

        const nextTier = royalePassTiers.find(t => t.level === level + 1);
        const totalXpForNext = nextTier ? nextTier.xp : totalXpForLevel;
        const xpForLevelVal = totalXpForNext - totalXpForLevel;
        const xpInLevel = playerPass.xp - totalXpForLevel;

        return { currentLevel: level, xpForNextLevel: xpForLevelVal, xpInCurrentLevel: xpInLevel, totalXpForNextLevel: totalXpForNext };
    }, [playerPass, royalePassTiers]);


    if (contentLoading) {
        return <div className="flex justify-center p-8"><Spinner /></div>;
    }

    if (!playerPass) {
        return <div className="p-8 text-center">Royale Pass data not available. Please try again later.</div>
    }

    const progressPercent = totalXpForNextLevel > playerPass.xp ? (xpInCurrentLevel / xpForNextLevel) * 100 : 100;

    return (
        <div className="w-full h-full flex flex-col space-y-2">
            <h2 className="text-xl text-center font-bold text-yellow-400 flex-shrink-0" style={{ textShadow: '2px 2px 0 #000' }}>Royale Pass</h2>

            {/* Progress and Activation - Fixed at top */}
            <div className="p-2 sm:p-3 bg-[#2c2c54] border-2 border-black shadow-[4px_4px_0px_#000000] flex-shrink-0">
                <div className="flex justify-between items-center mb-2">
                    <span className="px-2 py-1 bg-black border-2 border-yellow-400 text-sm font-bold">LVL {currentLevel}</span>
                    {!playerPass.hasPremium ? (
                        <Button onClick={handleActivatePass} disabled={loadingAction} variant="success" className="!py-1 !px-2 !text-xs">
                            {loadingAction ? <Spinner /> : 'Activate 💎 500'}
                        </Button>
                    ) : <span className="text-purple-300 font-bold text-sm">PREMIUM ACTIVE</span>}
                </div>
                <div className="w-full bg-black h-4 border-2 border-black p-0.5">
                    <div className="h-full bg-yellow-400 transition-all duration-500 relative" style={{ width: `${progressPercent}%` }}>
                        <span className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 text-black text-[9px] font-bold whitespace-nowrap">{playerPass.xp} / {totalXpForNextLevel} XP</span>
                    </div>
                </div>
            </div>

            {/* Scrollable Tiers List */}
            <div className="flex-grow overflow-y-auto space-y-2 pr-1">
                {royalePassTiers.map(tier => {
                    const isUnlocked = playerPass.xp >= tier.xp;
                    const isFreeClaimed = playerPass.claimedRewards?.[tier.level]?.includes('free');
                    const isPremiumClaimed = playerPass.claimedRewards?.[tier.level]?.includes('premium');
                    const canClaimFree = isUnlocked && tier.freeReward && !isFreeClaimed;
                    const canClaimPremium = isUnlocked && tier.premiumReward && !isPremiumClaimed && playerPass.hasPremium;

                    return (
                        <div key={tier.id} className={`p-1 border-2 border-black grid grid-cols-6 items-center gap-1 ${isUnlocked ? 'bg-gray-800/80' : 'bg-gray-900/50'}`}>
                            <div className="col-span-1 text-center font-bold text-sm p-1 bg-black border border-gray-600">
                                {tier.level}
                            </div>
                            {/* Free Reward */}
                            <div className={`col-span-2 p-1 border border-black text-center ${isUnlocked ? 'bg-yellow-800/30' : 'bg-gray-800/30'}`}>
                                <p className="text-[9px] text-yellow-300 uppercase">Free</p>
                                {tier.freeReward ? (
                                    <div className="flex flex-col items-center">
                                        <p className="text-xl">{tier.freeReward.icon}</p>
                                        <Button onClick={() => handleClaim(tier, 'free')} disabled={!canClaimFree || !!claimingId} className="!text-[9px] !py-0.5 !px-1 mt-1 w-full max-w-[60px]">
                                            {claimingId === `${tier.id}-free` ? <Spinner/> : isFreeClaimed ? 'Claimed' : 'Claim'}
                                        </Button>
                                    </div>
                                ) : <p className="text-gray-500 text-[9px] py-1">Empty</p>}
                            </div>
                            {/* Premium Reward */}
                            <div className={`col-span-3 p-1 border border-black text-center ${playerPass.hasPremium ? 'border-purple-400 bg-purple-900/30' : 'bg-gray-800/30'}`}>
                                <p className="text-[9px] text-purple-300 uppercase">Premium</p>
                                {tier.premiumReward ? (
                                     <div className="flex flex-col items-center">
                                        <p className="text-xl">{tier.premiumReward.icon}</p>
                                        <Button onClick={() => handleClaim(tier, 'premium')} disabled={!canClaimPremium || !!claimingId} className="!text-[9px] !py-0.5 !px-1 mt-1 w-full max-w-[60px]">
                                            {claimingId === `${tier.id}-premium` ? <Spinner/> : isPremiumClaimed ? 'Claimed' : playerPass.hasPremium ? 'Claim' : 'Locked'}
                                        </Button>
                                    </div>
                                ) : <p className="text-gray-500 text-[9px] py-1">Empty</p>}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

export default RoyalePassScreen;

import React, { useState, useEffect } from 'react';
// Fix: Removed 'RankInfo' from import as it's not exported from '../types' and is not used.
import type { Player, Clan, RankTier } from '../types';
import { rtdb } from '../services/firebase';
import type firebase from 'firebase/compat/app';
import { Spinner } from './common/Spinner';
import PlayerAvatar from './common/PlayerAvatar';
import { getRankInfo } from '../utils/helpers';
import { FALLBACK_BOT_NAMES } from '../constants';
import { toast } from 'react-toastify';

type LeaderboardTab = 'players' | 'clans';
type PlayerFilter = 'all-time' | 'weekly' | 'daily';

interface LeaderboardProps {
  onViewProfile: (uid: string) => void;
}

const generateBotPlayers = (): Player[] => {
  const bots: Player[] = [];
  const shuffledNames = [...FALLBACK_BOT_NAMES].sort(() => 0.5 - Math.random());

  for (let i = 0; i < 100; i++) {
    let rankPoints = 0;
    if (i < 3) {
      rankPoints = 4000 + Math.floor(Math.random() * 500); // Grandmaster
    } else if (i < 10) {
      rankPoints = 3600 + Math.floor(Math.random() * 400); // Master
    } else if (i < 25) {
      rankPoints = 3200 + Math.floor(Math.random() * 400); // Heroic
    } else if (i < 50) {
      rankPoints = 2500 + Math.floor(Math.random() * 700); // Diamond
    } else {
      rankPoints = 1200 + Math.floor(Math.random() * 1300); // Silver/Gold
    }

    const botName = shuffledNames[i % shuffledNames.length];
    const botUid = `bot_${i}_${botName}_${rankPoints}`;

    bots.push({
      uid: botUid,
      displayName: botName,
      photoURL: `https://api.dicebear.com/7.x/pixel-art/svg?seed=${botUid}`,
      rankPoints,
      coins: Math.floor(Math.random() * 10000),
      gems: Math.floor(Math.random() * 500),
      level: Math.floor(Math.random() * 50) + 10,
      xp: 0,
      xpToNextLevel: 100,
      clanId: null,
      lastLogin: Date.now() - Math.floor(Math.random() * 1000 * 60 * 60 * 24 * 7),
      email: null,
      mineCapacity: 0,
      mineLastCollected: 0,
      mineRate: 0,
      nfts: [],
      hasCompletedTutorial: true,
    });
  }
  return bots;
};

const Leaderboard: React.FC<LeaderboardProps> = ({ onViewProfile }) => {
  const [activeTab, setActiveTab] = useState<LeaderboardTab>('players');
  const [playerFilter, setPlayerFilter] = useState<PlayerFilter>('all-time');
  const [topPlayers, setTopPlayers] = useState<Player[]>([]);
  const [topClans, setTopClans] = useState<Clan[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    setLoading(true);
    setError(null);
    let ref: firebase.database.Query;
    let listener: (snapshot: firebase.database.DataSnapshot) => void;

    if (activeTab === 'players') {
      const orderBy = playerFilter === 'daily' ? 'dailyRankPoints' : playerFilter === 'weekly' ? 'weeklyRankPoints' : 'rankPoints';
      ref = rtdb.ref('users').orderByChild(orderBy).limitToLast(100);
      listener = (snapshot: firebase.database.DataSnapshot) => {
        const realPlayers: Player[] = [];
        if(snapshot.exists()) {
            snapshot.forEach(child => {
                const player = child.val() as Player;
                if ((player[orderBy as keyof Player] as number || 0) > 0) {
                   realPlayers.push(player);
                }
            });
        }

        if (playerFilter === 'all-time') {
            const botPlayers = generateBotPlayers();
            const allPlayers = [...realPlayers, ...botPlayers];
            allPlayers.sort((a, b) => (b.rankPoints || 0) - (a.rankPoints || 0));
            setTopPlayers(allPlayers.slice(0, 100));
        } else {
            realPlayers.sort((a, b) => (b[orderBy as keyof Player] as number || 0) - (a[orderBy as keyof Player] as number || 0));
            setTopPlayers(realPlayers);
        }
        setLoading(false);
      };
    } else { // activeTab === 'clans'
      ref = rtdb.ref('clans').orderByChild('totalRankPoints').limitToLast(10);
      listener = (snapshot: firebase.database.DataSnapshot) => {
        const clans: Clan[] = [];
         if(snapshot.exists()) {
            snapshot.forEach(child => {
                clans.push(child.val());
            });
        }
        setTopClans(clans.reverse());
        setLoading(false);
      };
    }

    ref.on('value', listener, (err: Error) => {
        console.error("Leaderboard listener failed:", err);
        setError(`Could not load ${activeTab} leaderboard due to a permission issue.`);
        setLoading(false);
    });

    return () => ref.off('value', listener);
  }, [activeTab, playerFilter]);

  const renderPlayerList = () => {
    const orderBy = playerFilter === 'daily' ? 'dailyRankPoints' : playerFilter === 'weekly' ? 'weeklyRankPoints' : 'rankPoints';
    return (
        <ul className="space-y-1">
        {topPlayers.map((player, index) => {
            const { rankName, tier } = getRankInfo(player.rankPoints);
            const score = (player[orderBy as keyof Player] as number) || 0;
            return (
                <li 
                    key={player.uid} 
                    className="flex items-center justify-between p-1.5 bg-gray-900 border border-gray-700 text-xs transition-colors hover:bg-gray-800 cursor-pointer"
                    onClick={() => onViewProfile(player.uid)}
                >
                <div className="flex items-center space-x-2">
                    <span className={`font-bold text-xs w-6 text-center ${index < 3 ? 'text-yellow-400 text-sm' : 'text-gray-400'}`}>{index + 1}</span>
                    <PlayerAvatar 
                        photoURL={player.photoURL}
                        uid={player.uid}
                        activeBadge={player.activeBadge}
                        sizeClassName="w-6 h-6"
                        imgClassName="bg-gray-700 border border-black"
                    />
                    <span className="truncate max-w-[100px] sm:max-w-none">{player.displayName || 'Anonymous'}</span>
                </div>
                <div className="flex items-center gap-1.5">
                    <span className="text-base" title={rankName}>{tier.icon}</span>
                    <span className="font-semibold text-blue-400">{score.toLocaleString()} RP</span>
                </div>
                </li>
            );
        })}
        </ul>
    );
  };

  const renderClanList = () => (
      <ul className="space-y-1">
      {topClans.map((clan, index) => (
        <li key={clan.id} className="flex items-center justify-between p-2 bg-gray-900 border border-gray-700 text-xs">
          <div className="flex items-center space-x-2">
            <span className={`font-bold text-xs w-6 text-center ${index < 3 ? 'text-yellow-400 text-sm' : 'text-gray-400'}`}>{index + 1}</span>
            <div>
                 <p className="font-bold">{clan.name} <span className="text-gray-400">[{clan.tag}]</span></p>
                 <p className="text-[10px] text-gray-500">{clan.memberCount} members</p>
            </div>
          </div>
          <span className="font-semibold text-blue-400">{clan.totalRankPoints} RP</span>
        </li>
      ))}
    </ul>
  );

  return (
    <div className="w-full h-full flex flex-col bg-[#2c2c54] border-2 border-black shadow-[4px_4px_0px_#000000]">
      {/* Tabs Header */}
      <div className="flex-shrink-0 border-b-2 border-black">
          <div className="flex">
            <button 
            onClick={() => setActiveTab('players')}
            className={`flex-1 py-2 font-bold text-xs sm:text-sm transition-colors ${activeTab === 'players' ? 'bg-yellow-400 text-black' : 'bg-[#1a1a2e] text-white hover:bg-gray-800'}`}
            >
                Players
            </button>
            <button 
            onClick={() => setActiveTab('clans')}
            className={`flex-1 py-2 font-bold text-xs sm:text-sm transition-colors ${activeTab === 'clans' ? 'bg-yellow-400 text-black' : 'bg-[#1a1a2e] text-white hover:bg-gray-800'}`}
            >
                Clans
            </button>
          </div>

        {activeTab === 'players' && (
            <div className="flex border-t border-black bg-black/20">
                {['all-time', 'weekly', 'daily'].map((filter) => (
                    <button 
                        key={filter}
                        onClick={() => setPlayerFilter(filter as PlayerFilter)} 
                        className={`flex-1 py-1.5 font-bold text-[10px] sm:text-xs uppercase transition-colors ${playerFilter === filter ? 'text-yellow-400 bg-black/40' : 'text-gray-400 hover:bg-black/20'}`}
                    >
                        {filter}
                    </button>
                ))}
            </div>
        )}
      </div>

      {/* Scrollable Content */}
      <div className="flex-grow overflow-y-auto p-2">
        {error && <div className="text-center text-red-400 text-sm">{error}</div>}
        {loading ? (
            <div className="flex justify-center p-4"><Spinner /></div>
        ) : !error ? (
            activeTab === 'players' ? renderPlayerList() : renderClanList()
        ) : null}
      </div>
    </div>
  );
};

export default Leaderboard;

import React, { useState, useMemo } from 'react';
import type { Player, Bird } from '../types';
import Button from './common/Button';
import { useAuth } from '../hooks/useAuth';
import { INSECT_DEFINITIONS } from '../constants';
import * as playerService from '../services/playerService';
import { toast } from 'react-toastify';
import { Spinner } from './common/Spinner';
import BirdIcon from './common/BirdIcon';

interface BirdsScreenProps {
  player: Player;
}

const MyBirdsView: React.FC<{ player: Player }> = ({ player }) => {
  const { user } = useAuth();
  const [selectedBird, setSelectedBird] = useState<Bird | null>(null);
  const [feeding, setFeeding] = useState(false);
  const [equipping, setEquipping] = useState(false);

  const ownedBirds = useMemo(() => {
    return player.ownedBirds ? Object.values(player.ownedBirds) : [];
  }, [player.ownedBirds]);

  const ownedInsects = useMemo(() => {
    return player.inventory?.insects ? Object.entries(player.inventory.insects) : [];
  }, [player.inventory?.insects]);

  const handleFeed = async (insectId: string) => {
    if (!user || !selectedBird || feeding) return;
    setFeeding(true);
    try {
      await playerService.feedBird(user.uid, selectedBird.id, insectId);
      toast.success(`${selectedBird.name} enjoyed the meal!`);
      setSelectedBird(null); // Close modal on success
    } catch (e: any) {
      toast.error(e.message);
    } finally {
      setFeeding(false);
    }
  };

  const handleEquip = async (birdId: string) => {
    if (!user) return;
    setEquipping(true);
    try {
        await playerService.equipBird(user.uid, birdId);
        toast.success("Bird equipped!");
    } catch(e: any) {
        toast.error("Failed to equip bird.");
    } finally {
        setEquipping(false);
    }
  }

  const FeedModal: React.FC = () => {
    if (!selectedBird) return null;
    return (
      <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4" onClick={() => setSelectedBird(null)}>
        <div className="w-full max-w-sm p-4 bg-[#2c2c54] border-2 border-black shadow-[6px_6px_0px_#000000]" onClick={e => e.stopPropagation()}>
          <h3 className="text-lg font-bold text-center mb-3">Feed {selectedBird.name}</h3>
          {ownedInsects.length > 0 ? (
            <div className="space-y-2 max-h-60 overflow-y-auto">
              {ownedInsects.map(([id, count]) => {
                const insectInfo = INSECT_DEFINITIONS[id];
                if (!insectInfo) return null;
                return (
                  <div key={id} className="flex items-center justify-between p-2 bg-gray-900 border-2 border-black">
                    <div className="flex items-center">
                        <span className="text-3xl mr-2 transition-transform duration-200 pseudo-3d-item">{insectInfo.icon}</span>
                        <div>
                            <p className="font-bold">{insectInfo.name} (x{count})</p>
                            <p className="text-xs text-yellow-300">+{insectInfo.xpValue} XP</p>
                        </div>
                    </div>
                    <Button onClick={() => handleFeed(id)} disabled={feeding} className="!py-1 !px-2 !text-xs">
                      Feed
                    </Button>
                  </div>
                )
              })}
            </div>
          ) : (
            <p className="text-center text-gray-400 py-4">You have no food! Buy some from the store.</p>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="h-full flex flex-col">
      {ownedBirds.length > 0 ? (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-2 overflow-y-auto p-1">
          {ownedBirds.map(bird => {
            const progress = bird.xpToNextLevel > 0 ? (bird.xp / bird.xpToNextLevel) * 100 : 100;
            const isEquipped = player.equippedBirdId === bird.id;
            return (
              <div key={bird.id} className="p-2 bg-[#2c2c54] border-2 border-black shadow-[2px_2px_0px_#000000] flex flex-col items-center text-center">
                  <div className="relative">
                    <BirdIcon bird={bird} className="text-4xl" imgClassName="w-12 h-12" />
                    {isEquipped && <span className="absolute -top-2 -right-2 text-xs bg-green-600 text-white px-1 rounded border border-black">EQP</span>}
                  </div>

                  <div className="mt-1 w-full">
                      <h3 className="font-bold text-xs truncate">{bird.name}</h3>
                      <p className="text-[10px] text-gray-400">Lvl {bird.level}</p>
                  </div>

                  <div className="w-full bg-black h-2 border border-gray-600 my-1">
                    <div className="h-full bg-yellow-400 relative" style={{ width: `${progress}%` }}></div>
                  </div>

                  <div className="flex gap-1 w-full mt-auto">
                     <Button onClick={() => handleEquip(bird.id)} disabled={isEquipped || equipping} variant={isEquipped ? 'secondary' : 'primary'} className="!py-0.5 !px-1 !text-[10px] flex-1">
                        {isEquipped ? 'Used' : 'Equip'}
                    </Button>
                    <Button onClick={() => setSelectedBird(bird)} className="!py-0.5 !px-1 !text-[10px] flex-1">Feed</Button>
                  </div>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="flex-grow flex flex-col items-center justify-center p-8">
          <p className="text-gray-400 text-sm">You don't own any birds yet.</p>
          <p className="text-gray-400 text-sm mt-1">Visit the <span className="font-bold text-yellow-400">Store</span> to get your first bird!</p>
        </div>
      )}
      <FeedModal />
    </div>
  );
};

const TrainingView: React.FC<{ player: Player }> = ({ player }) => {
    const { user } = useAuth();
    const [selectedBird, setSelectedBird] = useState<Bird | null>(null);
    const [upgrading, setUpgrading] = useState<'skillPower' | 'maxHealth' | null>(null);

    const ownedBirds = useMemo(() => player.ownedBirds ? Object.values(player.ownedBirds) : [], [player.ownedBirds]);

    const handleUpgrade = async (stat: 'skillPower' | 'maxHealth') => {
        if (!user || !selectedBird || upgrading) return;
        setUpgrading(stat);
        try {
            await playerService.upgradeBirdStat(user.uid, selectedBird.id, stat);
            toast.success(`${stat === 'skillPower' ? 'Power' : 'Health'} upgraded!`);
            const updatedBird = player.ownedBirds?.[selectedBird.id];
            if (updatedBird) setSelectedBird(updatedBird);

        } catch (e: any) {
            toast.error(e.message);
        } finally {
            setUpgrading(null);
        }
    };

    React.useEffect(() => {
        if (selectedBird) {
            const updatedBird = player.ownedBirds?.[selectedBird.id];
            if(updatedBird) setSelectedBird(updatedBird);
        }
    }, [player.ownedBirds, selectedBird]);

    if (selectedBird) {
        const powerLevel = selectedBird.powerLevel || 1;
        const healthLevel = selectedBird.healthLevel || 1;
        const powerCost = Math.floor(250 * Math.pow(powerLevel, 1.2));
        const healthCost = Math.floor(250 * Math.pow(healthLevel, 1.2));

        return (
             <div className="h-full flex flex-col p-2 space-y-2">
                 <div className="flex items-center gap-4 bg-[#2c2c54] p-3 border-2 border-black">
                    <BirdIcon bird={selectedBird} className="text-5xl" imgClassName="w-12 h-12" />
                    <div>
                      <h3 className="font-bold">{selectedBird.name} <span className="text-xs text-gray-400">(Lv. {selectedBird.level})</span></h3>
                    </div>
                </div>

                <div className="flex-grow space-y-2 overflow-y-auto">
                    <div className="p-3 bg-gray-900 border-2 border-black flex items-center justify-between">
                        <div>
                            <p className="font-bold">Skill Power <span className="text-xs text-gray-400">(Lvl {powerLevel})</span></p>
                            <p className="text-sm">⚔️ <span className="text-yellow-400">{selectedBird.skillPower}</span> → <span className="text-green-400">{selectedBird.skillPower + 5}</span></p>
                        </div>
                        <Button onClick={() => handleUpgrade('skillPower')} disabled={!!upgrading} className="!py-2 !text-xs">
                            {upgrading === 'skillPower' ? <Spinner /> : `Upgrade 💰${powerCost}`}
                        </Button>
                    </div>
                     <div className="p-3 bg-gray-900 border-2 border-black flex items-center justify-between">
                        <div>
                            <p className="font-bold">Max Health <span className="text-xs text-gray-400">(Lvl {healthLevel})</span></p>
                            <p className="text-sm">❤️ <span className="text-red-400">{selectedBird.maxHealth}</span> → <span className="text-green-400">{selectedBird.maxHealth + 20}</span></p>
                        </div>
                        <Button onClick={() => handleUpgrade('maxHealth')} disabled={!!upgrading} className="!py-2 !text-xs">
                             {upgrading === 'maxHealth' ? <Spinner /> : `Upgrade 💰${healthCost}`}
                        </Button>
                    </div>
                </div>
                 <Button onClick={() => setSelectedBird(null)} variant="secondary" className="w-full mt-auto">Back</Button>
             </div>
        )
    }

    return (
        <div className="h-full flex flex-col">
            <p className="text-center text-xs text-gray-300 p-2">Select a bird to train.</p>
            <div className="flex-grow overflow-y-auto space-y-2 p-1">
                {ownedBirds.map(bird => (
                    <button key={bird.id} onClick={() => setSelectedBird(bird)} className="w-full p-2 bg-[#2c2c54] border-2 border-black flex items-center gap-3 hover:bg-gray-800 transition-colors">
                        <BirdIcon bird={bird} className="text-4xl" imgClassName="w-10 h-10" />
                        <div className="text-left">
                            <h3 className="font-bold text-sm">{bird.name}</h3>
                            <div className="flex gap-2 text-xs">
                                <span>⚔️ {bird.skillPower}</span>
                                <span>❤️ {bird.maxHealth}</span>
                            </div>
                        </div>
                    </button>
                ))}
            </div>
        </div>
    );
};

const EmotesView: React.FC<{ player: Player }> = ({ player }) => {
    const { user } = useAuth();
    const [selectedEmotes, setSelectedEmotes] = useState<Set<string>>(() => new Set(player.equippedEmotes || []));
    const [saving, setSaving] = useState(false);

    const ownedEmotes = useMemo(() => player.ownedEmotes || [], [player.ownedEmotes]);

    const handleToggleEmote = (emote: string) => {
        setSelectedEmotes(prev => {
            const newSet = new Set(prev);
            if (newSet.has(emote)) {
                newSet.delete(emote);
            } else if (newSet.size < 6) {
                newSet.add(emote);
            } else {
                toast.info("You can only equip up to 6 emotes.");
            }
            return newSet;
        });
    };

    const handleSave = async () => {
        if (!user) return;
        setSaving(true);
        try {
            await playerService.equipEmotes(user.uid, Array.from(selectedEmotes));
            toast.success("Emotes equipped!");
        } catch (e: any) {
            toast.error(e.message);
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="h-full flex flex-col space-y-4 overflow-y-auto p-1">
            <div className="p-2 bg-gray-900 border-2 border-black flex-shrink-0">
                <h3 className="font-bold text-center text-sm mb-2">Equipped ({selectedEmotes.size}/6)</h3>
                <div className="flex flex-wrap gap-2 justify-center">
                    {Array.from(selectedEmotes).map(emote => (
                        <div key={emote} className="text-2xl p-1 bg-gray-800 rounded">{emote}</div>
                    ))}
                </div>
            </div>

            <div className="flex-grow space-y-2">
                <h3 className="font-bold text-center text-sm">Collection</h3>
                {ownedEmotes.length > 0 ? (
                    <div className="grid grid-cols-5 gap-2">
                    {ownedEmotes.map(emote => (
                        <button 
                            key={emote}
                            onClick={() => handleToggleEmote(emote)}
                            className={`p-2 border-2 border-black text-2xl transition-all ${selectedEmotes.has(emote) ? 'bg-blue-600' : 'bg-gray-800'}`}
                        >
                            {emote}
                        </button>
                    ))}
                    </div>
                ) : (
                    <p className="text-center text-sm text-gray-400">Purchase emotes from the Store!</p>
                )}
            </div>

            <Button onClick={handleSave} disabled={saving} className="w-full flex-shrink-0">
                {saving ? <Spinner/> : "Save"}
            </Button>
        </div>
    );
};

